L1: package fan.summer.api.component;
L2: 
L3: import javafx.animation.*;
L4: import javafx.geometry.*;
L5: import javafx.scene.Node;
L6: import javafx.scene.control.*;
L7: import javafx.scene.layout.*;
L8: import javafx.scene.paint.Color;
L9: import javafx.scene.shape.*;
L10: import javafx.util.Duration;
L11: 
L12: import java.util.ArrayList;
L13: import java.util.List;
L14: import java.util.function.BooleanSupplier;
L15: 
L16: /**
L17:  * Generic multi-step wizard container.
L18:  *
L19:  * Usage:
L20:  *   wizard.addStep("Select file", node, () -> validate());
L21:  *   wizard.addStep("Split mode",  node, () -> true);
L22:  *   wizard.addStep("Run split",   node, () -> true);
L23:  *   wizard.build();
L24:  */
L25: public class StepWizard extends BorderPane {
L26: 
L27:     public interface StepChangeListener {
L28:         void onStepChanged(int from, int to, int total);
L29:     }
L30: 
L31:     private record Step(String title, Node content, BooleanSupplier canProceed) {}
L32: 
L33:     // ── State ─────────────────────────────────────────────
L34:     private final List<Step>   steps       = new ArrayList<>();
L35:     private int                current     = 0;
L36:     private StepChangeListener stepListener;
L37: 
L38:     // ── Fixed child nodes ─────────────────────────────────
L39:     private HBox   stepIndicator;
L40:     private StackPane contentPane;
L41:     private Button prevBtn;
L42:     private Button nextBtn;
L43:     private Label  stepHint;
L44: 
L45:     // ── Colour constants ──────────────────────────────────
L46:     private static final String ACCENT     = "#5b8cf7";
L47:     private static final String DONE_COLOR = "#4cd97b";
L48:     private static final String IDLE_COLOR = "rgba(255,255,255,0.15)";
L49: 
L50:     public StepWizard() {
L51:         setStyle("-fx-background-color: transparent;");
L52:     }
L53: 
L54:     public void addStep(String title, Node content, BooleanSupplier canProceed) {
L55:         steps.add(new Step(title, content, canProceed));
L56:     }
L57: 
L58:     public void setOnStepChanged(StepChangeListener l) { this.stepListener = l; }
L59: 
L60:     /** Called once after all steps are added to build UI */
L61:     public void build() {
L62:         stepIndicator = buildStepIndicator();
L63:         contentPane   = new StackPane();
L64:         contentPane.setStyle("-fx-background-color: transparent;");
L65: 
L66:         // Preload all content, opacity 0, only show current step
L67:         for (Step s : steps) {
L68:             s.content().setOpacity(0);
L69:             s.content().setVisible(false);
L70:             contentPane.getChildren().add(s.content());
L71:         }
L72: 
L73:         HBox footer = buildFooter();
L74: 
L75:         VBox top = new VBox(stepIndicator);
L76:         top.setPadding(new Insets(0, 0, 20, 0));
L77: 
L78:         setTop(top);
L79:         setCenter(contentPane);
L80:         setBottom(footer);
L81:         BorderPane.setMargin(footer, new Insets(16, 0, 0, 0));
L82: 
L83:         // Show the first step
L84:         showStep(0, -1);
L85:     }
L86: 
L87:     // ── Step indicator ────────────────────────────────────────
L88: 
L89:     private HBox buildStepIndicator() {
L90:         HBox row = new HBox();
L91:         row.setAlignment(Pos.CENTER);
L92:         row.setPadding(new Insets(0, 0, 4, 0));
L93: 
L94:         for (int i = 0; i < steps.size(); i++) {
L95:             // Circular step dot
L96:             StackPane dot = makeDot(i);
L97:             dot.setUserData(i); // Store index for refresh use
L98:             row.getChildren().add(dot);
L99: 
L100:             // Connector line (not added after last)
L101:             if (i < steps.size() - 1) {
L102:                 Region line = new Region();
L103:                 line.setPrefHeight(2);
L104:                 line.setMaxHeight(2);
L105:                 line.setMinWidth(40);
L106:                 HBox.setHgrow(line, Priority.ALWAYS);
L107:                 line.setStyle("-fx-background-color: " + IDLE_COLOR + "; -fx-background-radius: 1;");
L108:                 line.setUserData("line_" + i);
L109:                 row.getChildren().add(line);
L110:             }
L111:         }
L112:         return row;
L113:     }
L114: 
L115:     private StackPane makeDot(int idx) {
L116:         Circle circle = new Circle(12);
L117:         circle.setStrokeWidth(1.5);
L118: 
L119:         Label num = new Label(String.valueOf(idx + 1));
L120:         num.setStyle("-fx-font-size: 11px; -fx-font-weight: bold;");
L121: 
L122:         StackPane dot = new StackPane(circle, num);
L123:         dot.setPrefSize(24, 24);
L124:         return dot;
L125:     }
L126: 
L127:     /** Refresh all step dots and connector line styles */
L128:     private void refreshIndicator() {
L129:         int childIdx = 0;
L130:         for (int i = 0; i < steps.size(); i++) {
L131:             if (childIdx >= stepIndicator.getChildren().size()) break;
L132:             StackPane dot    = (StackPane) stepIndicator.getChildren().get(childIdx);
L133:             Circle    circle = (Circle)    dot.getChildren().get(0);
L134:             Label     num    = (Label)     dot.getChildren().get(1);
L135:             childIdx++;
L136: 
L137:             if (i < current) {
L138:                 circle.setFill(Color.web(DONE_COLOR, 0.9));
L139:                 circle.setStroke(Color.web(DONE_COLOR));
L140:                 num.setText("✓");
L141:                 num.setStyle("-fx-font-size: 11px; -fx-font-weight: bold; -fx-text-fill: #0d0e11;");
L142:             } else if (i == current) {
L143:                 circle.setFill(Color.web(ACCENT, 0.9));
L144:                 circle.setStroke(Color.web(ACCENT));
L145:                 num.setText(String.valueOf(i + 1));
L146:                 num.setStyle("-fx-font-size: 11px; -fx-font-weight: bold; -fx-text-fill: white;");
L147:                 ScaleTransition pulse = new ScaleTransition(Duration.millis(600), dot);
L148:                 pulse.setFromX(1.0); pulse.setFromY(1.0);
L149:                 pulse.setToX(1.12); pulse.setToY(1.12);
L150:                 pulse.setAutoReverse(true); pulse.setCycleCount(2);
L151:                 pulse.play();
L152:             } else {
L153:                 circle.setFill(Color.web("rgba(255,255,255,0.06)"));
L154:                 circle.setStroke(Color.web(IDLE_COLOR));
L155:                 num.setText(String.valueOf(i + 1));
L156:                 num.setStyle("-fx-font-size: 11px; -fx-font-weight: bold; -fx-text-fill: rgba(255,255,255,0.35);");
L157:             }
L158: 
L159:             if (i < steps.size() - 1 && childIdx < stepIndicator.getChildren().size()) {
L160:                 Region line = (Region) stepIndicator.getChildren().get(childIdx);
L161:                 line.setStyle("-fx-background-color: "
L162:                     + (i < current ? DONE_COLOR : IDLE_COLOR)
L163:                     + "; -fx-background-radius: 1;");
L164:                 childIdx++;
L165:             }
L166:         }
L167:     }
L168: 
L169:     // ── Footer buttons ──────────────────────────────────────────
L170: 
L171:     private HBox buildFooter() {
L172:         prevBtn  = footerBtn("← ← Back", false);
L173:         nextBtn  = footerBtn("Next →", true);
L174:         stepHint = new Label();
L175:         stepHint.setStyle("-fx-text-fill: rgba(255,255,255,0.28); -fx-font-size: 11px;");
L176: 
L177:         prevBtn.setOnAction(e -> goTo(current - 1));
L178:         nextBtn.setOnAction(e -> {
L179:             Step s = steps.get(current);
L180:             if (!s.canProceed().getAsBoolean()) {
L181:                 shakeButton(nextBtn);
L182:                 return;
L183:             }
L184:             if (current < steps.size() - 1) goTo(current + 1);
L185:         });
L186: 
L187:         Region spacer = new Region();
L188:         HBox.setHgrow(spacer, Priority.ALWAYS);
L189: 
L190:         HBox footer = new HBox(12, prevBtn, spacer, stepHint, nextBtn);
L191:         footer.setAlignment(Pos.CENTER_LEFT);
L192:         return footer;
L193:     }
L194: 
L195:     private Button footerBtn(String text, boolean primary) {
L196:         Button btn = new Button(text);
L197:         if (primary) {
L198:             btn.setStyle(
L199:                 "-fx-background-color: #5b8cf7; -fx-text-fill: white;" +
L200:                 "-fx-font-size: 13px; -fx-font-weight: 500;" +
L201:                 "-fx-background-radius: 8; -fx-border-width: 0;" +
L202:                 "-fx-padding: 9 20 9 20; -fx-cursor: hand;"
L203:             );
L204:             btn.setOnMouseEntered(e -> btn.setStyle(btn.getStyle()
L205:                 .replace("#5b8cf7", "#4a7bf5")));
L206:             btn.setOnMouseExited(e -> btn.setStyle(btn.getStyle()
L207:                 .replace("#4a7bf5", "#5b8cf7")));
L208:         } else {
L209:             btn.setStyle(
L210:                 "-fx-background-color: rgba(255,255,255,0.07);" +
L211:                 "-fx-border-color: rgba(255,255,255,0.12); -fx-border-width: 1;" +
L212:                 "-fx-text-fill: rgba(255,255,255,0.7); -fx-font-size: 13px;" +
L213:                 "-fx-background-radius: 8; -fx-border-radius: 8;" +
L214:                 "-fx-padding: 9 20 9 20; -fx-cursor: hand;"
L215:             );
L216:         }
L217:         return btn;
L218:     }
L219: 
L220:     // ── Step transition ──────────────────────────────────────────
L221: 
L222:     public void goTo(int idx) {
L223:         if (idx < 0 || idx >= steps.size()) return;
L224:         int from = current;
L225:         current = idx;
L226:         showStep(idx, from);
L227:         if (stepListener != null) stepListener.onStepChanged(from, idx, steps.size());
L228:     }
L229: 
L230:     private void showStep(int idx, int from) {
L231:         refreshIndicator();
L232:         updateFooterState();
L233: 
L234:         Node incoming = steps.get(idx).content();
L235:         incoming.setVisible(true);
L236: 
L237:         if (from < 0) {
L238:             // Initial display, no animation needed
L239:             incoming.setOpacity(1);
L240:             return;
L241:         }
L242: 
L243:         // Determine slide direction
L244:         double dir = idx > from ? 1 : -1;
L245: 
L246:         // Hide old step
L247:         Node outgoing = steps.get(from).content();
L248:         TranslateTransition outTt = new TranslateTransition(Duration.millis(220), outgoing);
L249:         outTt.setToX(-dir * 40);
L250:         FadeTransition outFt = new FadeTransition(Duration.millis(220), outgoing);
L251:         outFt.setToValue(0);
L252:         ParallelTransition out = new ParallelTransition(outTt, outFt);
L253:         out.setOnFinished(e -> {
L254:             outgoing.setVisible(false);
L255:             outgoing.setTranslateX(0);
L256:         });
L257:         out.play();
L258: 
L259:         // Show new step
L260:         incoming.setTranslateX(dir * 40);
L261:         incoming.setOpacity(0);
L262:         TranslateTransition inTt = new TranslateTransition(Duration.millis(260), incoming);
L263:         inTt.setToX(0);
L264:         inTt.setInterpolator(Interpolator.SPLINE(0.4, 0.0, 0.2, 1.0));
L265:         FadeTransition inFt = new FadeTransition(Duration.millis(260), incoming);
L266:         inFt.setToValue(1);
L267:         new ParallelTransition(inTt, inFt).play();
L268:     }
L269: 
L270:     private void updateFooterState() {
L271:         prevBtn.setDisable(current == 0);
L272:         prevBtn.setOpacity(current == 0 ? 0.4 : 1.0);
L273: 
L274:         boolean isLast = current == steps.size() - 1;
L275:         nextBtn.setText(isLast ? "✓ Complete" : "Next →");
L276:         stepHint.setText("Step " + (current + 1) + "  of " + steps.size() + "  steps");
L277:     }
L278: 
L279:     /** Shake feedback when button validation fails */
L280:     private void shakeButton(Node node) {
L281:         TranslateTransition shake = new TranslateTransition(Duration.millis(60), node);
L282:         shake.setFromX(0); shake.setByX(8);
L283:         shake.setAutoReverse(true); shake.setCycleCount(4);
L284:         shake.play();
L285:     }
L286: 
L287:     // ── Public queries ──────────────────────────────────────────
L288: 
L289:     public int  getCurrentStep()  { return current; }
L290:     public int  getTotalSteps()   { return steps.size(); }
L291:     public boolean isLastStep()   { return current == steps.size() - 1; }
L292: }
