L13:     private final String id;
L14:     private final String i18nKey;
L15: 
L16:     ToolCategory(String id, String i18nKey) {
L17:         this.id = id;
L18:         this.i18nKey = i18nKey;
L19:     }
L20: 
L21:     /** Lowercase identifier matching the legacy string (e.g. "dev"). */
L22:     public String getId() { return id; }
L23: 
L24:     /** Key for i18n resource bundle lookups (e.g. "developer.tools"). */
L25:     public String getI18nKey() { return i18nKey; }
