L1: package fan.summer.api.log;
L2: 
L3: /**
L4:  * Entry point for plugins to obtain a {@link PluginLogger}.
L5:  *
L6:  * <pre>
L7:  *   public class MyPlugin implements SwissKitJPlugin {
L8:  *       private static final PluginLogger log =
L9:  *           LoggerFactory.getLogger(MyPlugin.class);
L10:  *       ...
L11:  *   }
L12:  * </pre>
L13:  *
L14:  * <p>The host application installs a real {@link LoggerBinder} during startup
L15:  * (typically backed by SLF4J + Logback). Until the host binds one, all loggers
L16:  * are silent no-ops — safe for unit tests and isolated plugin loading.</p>
L17:  */
L18: public final class LoggerFactory {
L19: 
L20:     private static volatile LoggerBinder binder = NoOpLoggerBinder.INSTANCE;
L21: 
L22:     private LoggerFactory() {
L23:     }
L24: 
L25:     /** Returns a logger named after the given class. */
L26:     public static PluginLogger getLogger(Class<?> clazz) {
L27:         return binder.getLogger(clazz.getName());
L28:     }
L29: 
L30:     /** Returns a logger with the given name (typically a dotted category). */
L31:     public static PluginLogger getLogger(String name) {
L32:         return binder.getLogger(name);
L33:     }
L34: 
L35:     /** Package-private — used by {@link LoggerBinder#bind(LoggerBinder)}. */
L36:     static void setBinder(LoggerBinder newBinder) {
L37:         binder = (newBinder == null) ? NoOpLoggerBinder.INSTANCE : newBinder;
L38:     }
L39: }
