L1: package fan.summer.api.theme;
L2: 
L3: import javafx.scene.Scene;
L4: 
L5: /**
L6:  * SwissKitJ 主题样式加载工具。
L7:  *
L8:  * <p>主程序在 Scene 上加载 {@link #commonStylesheetUrl()} 后，所有嵌入主 Scene 的
L9:  * 插件 Node 都自动继承共性样式。仅当插件自建独立 Stage / Scene 时才需要
L10:  * 调用 {@link #applyTo(Scene)} 主动加载。</p>
L11:  */
L12: public final class Themes {
L13: 
L14:     /** 共性样式表资源路径（位于本 jar 中）。 */
L15:     public static final String COMMON_CSS = "/css/swisskit-common.css";
L16: 
L17:     private Themes() {}
L18: 
L19:     /** 返回共性样式表的外部 URL，可直接放入 {@code Scene#getStylesheets()}。 */
L20:     public static String commonStylesheetUrl() {
L21:         return Themes.class.getResource(COMMON_CSS).toExternalForm();
L22:     }
L23: 
L24:     /** 对独立 Stage（弹窗 / 插件自带 Scene）一键应用基础主题，已加载则忽略。 */
L25:     public static void applyTo(Scene scene) {
L26:         if (scene == null) return;
L27:         String url = commonStylesheetUrl();
L28:         if (!scene.getStylesheets().contains(url)) {
L29:             scene.getStylesheets().add(url);
L30:         }
L31:     }
L32: }
