L1: package fan.summer;
L2: 
L3: import java.nio.file.Files;
L4: import java.nio.file.Path;
L5: 
L6: /**
L7:  * Fat JAR / classpath launch entry point.
L8:  *
L9:  * Must be separate from ToolboxApp (extends Application).
L10:  * JavaFX module system requires: when using a class that extends Application
L11:  * as the main class, javafx.graphics needs to be on the module-path,
L12:  * not classpath. Using this non-Application intermediate class for launch
L13:  * allows compatibility with classpath mode (lib/ directory).
L14:  *
L15:  * Also primes the logback log directory system property before any logger is
L16:  * initialised — must happen before the first SLF4J class is touched.
L17:  */
L18: public class Launcher {
L19: 
L20:     public static void main(String[] args) {
L21:         primeLogDirectory();
L22:         fan.summer.app.SwissKitJApp.main(args);
L23:     }
L24: 
L25:     /**
L26:      * Resolves and creates the log directory, then exports its absolute path as the
L27:      * {@code swisskit.log.dir} system property so that logback.xml can reference it.
L28:      * Honours an override if the user has already set the property externally.
L29:      */
L30:     private static void primeLogDirectory() {
L31:         if (System.getProperty("swisskit.log.dir") != null) {
L32:             return;
L33:         }
L34:         Path logDir = Path.of(System.getProperty("user.dir"), ".swisskit", "logs");
L35:         try {
L36:             Files.createDirectories(logDir);
L37:         } catch (Exception ignored) {
L38:             // Logback will fall back to a relative path; not fatal.
L39:         }
L40:         System.setProperty("swisskit.log.dir", logDir.toAbsolutePath().toString());
L41:     }
L42: }
