L1: package fan.summer.api.log;
L2: 
L3: /**
L4:  * Standard logging interface for SwissKitJ plugins.
L5:  *
L6:  * <p>Plugins obtain a logger via {@link LoggerFactory#getLogger(Class)} or
L7:  * {@link LoggerFactory#getLogger(String)} and call the level methods on it.
L8:  * Implementations are provided by the host application (typically backed by
L9:  * SLF4J + Logback), so plugins do not depend on any specific logging framework.</p>
L10:  *
L11:  * <p>Message formatting uses the SLF4J '{}' placeholder convention:</p>
L12:  * <pre>
L13:  *   logger.info("User {} loaded {} records", userName, count);
L14:  *   logger.error("Operation failed", exception);
L15:  *   logger.warn("Retrying {} (attempt {} of {})", taskId, attempt, maxAttempts);
L16:  * </pre>
L17:  *
L18:  * <p>All methods are safe to call from any thread.</p>
L19:  */
L20: public interface PluginLogger {
L21: 
L22:     /** @return the logger's name (typically a class or category name). */
L23:     String getName();
L24: 
L25:     // ── Trace ────────────────────────────────────────────────
L26:     boolean isTraceEnabled();
L27:     void trace(String message);
L28:     void trace(String format, Object arg);
L29:     void trace(String format, Object arg1, Object arg2);
L30:     void trace(String format, Object... args);
L31:     void trace(String message, Throwable t);
L32: 
L33:     // ── Debug ────────────────────────────────────────────────
L34:     boolean isDebugEnabled();
L35:     void debug(String message);
L36:     void debug(String format, Object arg);
L37:     void debug(String format, Object arg1, Object arg2);
L38:     void debug(String format, Object... args);
L39:     void debug(String message, Throwable t);
L40: 
L41:     // ── Info ─────────────────────────────────────────────────
L42:     boolean isInfoEnabled();
L43:     void info(String message);
L44:     void info(String format, Object arg);
L45:     void info(String format, Object arg1, Object arg2);
L46:     void info(String format, Object... args);
L47:     void info(String message, Throwable t);
L48: 
L49:     // ── Warn ─────────────────────────────────────────────────
L50:     boolean isWarnEnabled();
L51:     void warn(String message);
L52:     void warn(String format, Object arg);
L53:     void warn(String format, Object arg1, Object arg2);
L54:     void warn(String format, Object... args);
L55:     void warn(String message, Throwable t);
L56: 
